-- Season 24-25: Oklahoma City Thunder vs Indiana Pacers (Thunder won 4-3)

-- ============================================================
-- TABLE: Rankings
-- ============================================================
CREATE TABLE Rankings (
    RankingID INT PRIMARY KEY AUTO_INCREMENT,
    EquipoID INT NOT NULL,
    TemporadaID INT NOT NULL,
    Posicion INT,
    Puntos DECIMAL(10,2),
    Tipo VARCHAR(50),
    FechaActualizacion DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (EquipoID) REFERENCES Equipos(EquipoID),
    FOREIGN KEY (TemporadaID) REFERENCES Temporadas(TemporadaID),
    INDEX idx_equipo (EquipoID),
    INDEX idx_temporada (TemporadaID)
);

-- ============================================================
-- INSERT RANKINGS - CALCULATED FROM GAME RESULTS
-- ============================================================


-- ============================================================
-- TABLE: Predicciones (Predictions)
-- ============================================================
CREATE TABLE Predicciones (
    PrediccionID INT PRIMARY KEY AUTO_INCREMENT,
    PartidoID INT,
    EquipoFavoritoID INT,
    Confianza DECIMAL(5,2),
    Resultado VARCHAR(50),
    EsCorrecta BOOLEAN DEFAULT NULL,
    FechaCreacion DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (PartidoID) REFERENCES Partidos(PartidoID),
    FOREIGN KEY (EquipoFavoritoID) REFERENCES Equipos(EquipoID),
    INDEX idx_partido (PartidoID),
    INDEX idx_equipo (EquipoFavoritoID)
);

