SELECT COUNT(*) as TotalArenas FROM Arenas;
SELECT COUNT(*) as TotalPartidos FROM Partidos;
SELECT COUNT(*) as TotalTemporadas FROM Temporadas;
SELECT COUNT(*) as TotalClasificaciones FROM Clasificaciones;
SELECT COUNT(*) as TotalPlayoffs FROM Playoffs;
SELECT COUNT(*) as TotalRankings FROM Rankings;
SELECT COUNT(*) as TotalPredicciones FROM Predicciones;

